import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export type Language = 'ru' | 'ro';

export interface Translation {
  navHome: string;
  navVision: string;
  navServices: string;
  navContact: string;
  heroTitle: string;
  heroSubtitle: string;
  ctaVisit: string;
  visionTitle: string;
  visionText: string;
  serviceTitle: string;
  serviceMainTime: string;
  serviceMainLocation: string;
  serviceYouthTime: string;
  serviceSmallGroups: string;
  contactTitle: string;
  contactName: string;
  contactEmail: string;
  contactMessage: string;
  contactSend: string;
  assistantTitle: string;
  assistantPlaceholder: string;
  assistantGreeting: string;
}

export interface ChatMessage {
  role: 'user' | 'model';
  text: string;
}

import { GoogleGenAI } from "@google/genai";
import { ChatMessage, Language } from "../types";

const API_KEY = process.env.API_KEY;

export const generateAssistantResponse = async (
  message: string,
  history: ChatMessage[],
  lang: Language
) => {
  if (!API_KEY) {
    return "API Key not configured.";
  }

  const ai = new GoogleGenAI({ apiKey: API_KEY });
  const model = "gemini-3-flash-preview";

  const systemInstruction = `
    You are a friendly, modern, and spiritually wise assistant for "Church Without Walls" (Biserica Fără Ziduri / Церковь Без Стен) in Chișinău, Moldova.
    Your tone should be welcoming, inclusive, and non-judgmental.
    The church values: Community, Authentic Faith, Serving Chișinău, and Living without "walls" (meaning openness to all and influence beyond the building).
    Location: str. Sfatul Țării 17/1, Chișinău.
    Services: Sunday 11:00 AM, Youth Saturday 6:00 PM.
    Language: Please respond in ${lang === 'ru' ? 'Russian' : 'Romanian'}.
    If asked about deep theology, provide balanced biblical perspectives but always encourage visiting a service for deeper conversation.
  `;

  try {
    const chat = ai.chats.create({
      model,
      config: {
        systemInstruction,
        temperature: 0.7,
      }
    });

    // Convert history to Gemini format (excluding current message)
    // Note: This is simplified for the demo
    const response = await chat.sendMessage({ message });
    return response.text || "I'm sorry, I couldn't process that.";
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "The assistant is currently contemplating. Please try again in a moment.";
  }
};

import React, { useState, useEffect } from 'react';
import { Language } from './types';
import { translations } from './translations';
import Navbar from './components/Navbar';
import Hero from './components/Hero';
import Vision from './components/Vision';
import Services from './components/Services';
import Contact from './components/Contact';
import ChatAssistant from './components/ChatAssistant';
import Footer from './components/Footer';

const App: React.FC = () => {
  const [lang, setLang] = useState<Language>('ru');
  const t = translations[lang];

  // Set html lang attribute
  useEffect(() => {
    document.documentElement.lang = lang;
  }, [lang]);

  return (
    <div className="min-h-screen flex flex-col selection:bg-indigo-100 selection:text-indigo-900">
      <Navbar lang={lang} setLang={setLang} t={t} />

