const Logo: React.FC<LogoProps> = ({ className = "w-12 h-12", animate = true }) => {
  return (
    <motion.svg
      viewBox="0 0 100 100"
      className={className}
      initial={animate ? { rotate: -10, opacity: 0 } : {}}
