      transition={{ duration: 1, ease: [0.16, 1, 0.3, 1] }}
    >
      {/* 
        Recreating the interwoven 'Church Without Walls' logo.
        The logo consists of four overlapping colored loops forming a central knot.
      */}
      <defs>
        <filter id="shadow" x="-20%" y="-20%" width="140%" height="140%">
          <feGaussianBlur in="SourceAlpha" stdDeviation="1" />
          <feOffset dx="0" dy="1" result="offsetblur" />
          <feComponentTransfer>
            <feFuncA type="linear" slope="0.3" />
          </feComponentTransfer>
          <feMerge>
            <feMergeNode />
            <feMergeNode in="SourceGraphic" />
          </feMerge>
        </filter>
      </defs>

      {/* Blue path */}
      <path
        d="M20,50 Q20,30 50,30 T80,50 T50,70 T20,50"
        fill="none"
        stroke="#1d90a6"
        strokeWidth="6"
        strokeLinecap="round"
