        d="M30,40 Q50,10 70,40 T50,70 T30,40"
        fill="none"
        stroke="#549463"
        strokeWidth="6"
        strokeLinecap="round"
      />
      {/* Orange path */}
      <path
        d="M50,20 Q80,20 80,50 T50,80 T20,50 T50,20"
        fill="none"
        stroke="#f19e4b"
        strokeWidth="6"
        strokeLinecap="round"
      />
      {/* Red path */}
      <path
        d="M30,60 Q50,90 70,60 T50,30 T30,60"
        fill="none"
        stroke="#eb6e67"
        strokeWidth="6"
        strokeLinecap="round"
      />

      {/* Adding center connection details to mimic the interwoven look */}
