import React, { useRef } from 'react';
import { motion, useScroll, useTransform, useSpring, useMotionValue } from 'framer-motion';
import { Translation } from '../types';
import Logo from './Logo';

interface HeroProps {
  t: Translation;
}

const Hero: React.FC<HeroProps> = ({ t }) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const { scrollY } = useScroll();

  // Parallax effects
  const y = useTransform(scrollY, [0, 1000], [0, 400]);
  const opacity = useTransform(scrollY, [0, 600], [1, 0]);
  const rotateX = useTransform(scrollY, [0, 1000], [0, 15]);

  // Mouse interactivity
  const mouseX = useMotionValue(0);
  const mouseY = useMotionValue(0);
  const springX = useSpring(mouseX, { stiffness: 100, damping: 30 });
  const springY = useSpring(mouseY, { stiffness: 100, damping: 30 });

  const handleMouseMove = (e: React.MouseEvent) => {
    const { clientX, clientY, currentTarget } = e;
    const { width, height, left, top } = currentTarget.getBoundingClientRect();
    const x = (clientX - left) / width - 0.5;
    const y = (clientY - top) / height - 0.5;
    mouseX.set(x * 50);
    mouseY.set(y * 50);
  };

  const titleWords = t.heroTitle.split(' ');

  return (
    <div 
      ref={containerRef}
      onMouseMove={handleMouseMove}
      className="relative h-screen w-full flex items-center justify-center overflow-hidden bg-black"
    >
      {/* 3D Video Background */}
      <div className="absolute inset-0 z-0 scale-110">
        <video 
          autoPlay muted loop playsInline
          className="w-full h-full object-cover opacity-50 grayscale-[0.1]"
        >
          <source src="https://assets.mixkit.co/videos/preview/mixkit-audience-at-a-concert-applauding-and-waving-arms-42524-large.mp4" type="video/mp4" />
        </video>
        <div className="absolute inset-0 bg-gradient-to-b from-black via-transparent to-black"></div>
      </div>

      {/* Floating Interactive Elements */}
      <motion.div 
        style={{ x: springX, y: springY }}
        className="absolute inset-0 flex items-center justify-center pointer-events-none z-10"
      >
        <Logo className="w-[60vh] h-[60vh] opacity-10 blur-sm" animate={false} />
