import React, { useState, useEffect } from 'react';

const QUERY = '(prefers-reduced-motion: reduce)';

export function useReducedMotion(): boolean {
  const [matches, setMatches] = useState(false);

  useEffect(() => {
    const mediaQuery = window.matchMedia(QUERY);
    setMatches(mediaQuery.matches);

    const listener = (event: MediaQueryListEvent) => {
      setMatches(event.matches);
    };

    mediaQuery.addEventListener('change', listener);
    return () => mediaQuery.removeEventListener('change', listener);
  }, []);

  return matches;
}

import React from 'react';
import { motion } from 'framer-motion';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  children: React.ReactNode;
  variant?: 'primary' | 'secondary' | 'outline';
  className?: string;
  as?: 'button' | 'a';
  href?: string;
}

const Button: React.FC<ButtonProps> = ({ children, variant = 'primary', className = '', as = 'button', href, ...props }) => {
  const baseClasses = 'px-8 py-4 rounded-full font-semibold text-base tracking-wide transition-all duration-300 focus:outline-none focus:ring-4 focus:ring-opacity-50';

  const variantClasses = {
    primary: 'bg-[#0F172A] text-white hover:bg-[#1E293B] focus:ring-slate-400',
    secondary: 'bg-[#F59E0B] text-[#0F172A] hover:bg-[#FBBF24] focus:ring-amber-300 shadow-md shadow-amber-500/20',
    outline: 'bg-transparent border border-[#0F172A]/20 text-[#0F172A] hover:bg-[#0F172A] hover:text-white',
  };

  const motionProps = {
    whileHover: { scale: 1.05, y: -2 },
    whileTap: { scale: 0.95 },
    transition: { type: 'spring', stiffness: 400, damping: 15 },
  };

  const combinedClasses = `${baseClasses} ${variantClasses[variant]} ${className}`;

  if (as === 'a') {
    return (
      <motion.a href={href} className={combinedClasses} {...motionProps}>
        {children}
      </motion.a>
    );
  }

  return (
    <motion.button className={combinedClasses} {...props} {...motionProps}>
      {children}
    </motion.button>
  );
};

export default Button;

