import React, { Suspense, useMemo, useRef } from 'react';
import { motion } from 'framer-motion';
import { Canvas, useFrame } from '@react-three/fiber';
import * as THREE from 'three';
import { Translation } from '../../types';
import { useReducedMotion } from '../../hooks/useReducedMotion';
import Button from '../ui/Button';
import Container from '../layout/Container';

const vertexShader = `
uniform float uTime;
varying vec2 vUv;
void main() {
  vUv = uv;
  vec3 pos = position;
  pos.z += sin(pos.x * 2.0 + uTime * 0.5) * 0.02;
  pos.z += sin(pos.y * 3.0 + uTime * 0.3) * 0.03;
  gl_Position = projectionMatrix * modelViewMatrix * vec4(pos, 1.0);
}
`;

const fragmentShader = `
uniform float uTime;
uniform vec2 uMouse;
varying vec2 vUv;
void main() {
  vec2 uv = vUv - 0.5;
  float dist = length(uv - uMouse * 0.3);

  float r = 0.01 / dist;
  r += 0.02 / length(uv + vec2(0.5, 0.2) - uMouse * 0.2);

  float g = 0.01 / length(uv * 0.8 + vec2(0.3, -0.4) - uMouse * 0.4);

  float b = 0.02 / length(uv + vec2(-0.2, 0.3) - uMouse * 0.5);
  b += 0.01 / dist;

  vec3 color = vec3(r, g, b) * 0.3;
  gl_FragColor = vec4(color, 1.0);
}
`;

const LightWaves = () => {
  const materialRef = useRef<THREE.ShaderMaterial>(null!);
  const mouse = useRef({ x: 0, y: 0 });

  React.useEffect(() => {
    const handleMouseMove = (event: MouseEvent) => {
      mouse.current.x = (event.clientX / window.innerWidth) * 2 - 1;
      mouse.current.y = -(event.clientY / window.innerHeight) * 2 + 1;
    };
    window.addEventListener('mousemove', handleMouseMove);
    return () => window.removeEventListener('mousemove', handleMouseMove);
  }, []);

  useFrame(({ clock }) => {
    materialRef.current.uniforms.uTime.value = clock.getElapsedTime();
    materialRef.current.uniforms.uMouse.value.lerp(new THREE.Vector2(mouse.current.x, mouse.current.y), 0.05);
  });

  const uniforms = useMemo(
    () => ({
      uTime: { value: 0.0 },
      uMouse: { value: new THREE.Vector2(0, 0) },
    }), []
  );

  return (
    <mesh>
      <planeGeometry args={[10, 10, 64, 64]} />
      <shaderMaterial
        ref={materialRef}
        vertexShader={vertexShader}
        fragmentShader={fragmentShader}
        uniforms={uniforms}
        wireframe={false}
        blending={THREE.AdditiveBlending}
      />
    </mesh>
  );
};

