import React, { Suspense, useMemo, useRef, useState } from 'react';
import { motion } from 'framer-motion';
import { Canvas, useFrame } from '@react-three/fiber';
import * as THREE from 'three';
import { Points, PointMaterial } from '@react-three/drei';
import { Translation } from '../../types';
import { useReducedMotion } from '../../hooks/useReducedMotion';
import Button from '../ui/Button';
import Container from '../layout/Container';

const vertexShader = `
varying vec2 vUv;
void main() {
  vUv = uv;
  gl_Position = projectionMatrix * modelViewMatrix * vec4(position, 1.0);
}
`;

const fragmentShader = `
uniform float uTime;
varying vec2 vUv;

// Simplex noise function for organic patterns
vec3 mod289(vec3 x) { return x - floor(x * (1.0 / 289.0)) * 289.0; }
vec2 mod289(vec2 x) { return x - floor(x * (1.0 / 289.0)) * 289.0; }
vec3 permute(vec3 x) { return mod289(((x*34.0)+1.0)*x); }

float snoise(vec2 v) {
    const vec4 C = vec4(0.211324865405187, 0.366025403784439, -0.577350269189626, 0.024390243902439);
    vec2 i  = floor(v + dot(v, C.yy) );
    vec2 x0 = v -   i + dot(i, C.xx);
    vec2 i1 = (x0.x > x0.y) ? vec2(1.0, 0.0) : vec2(0.0, 1.0);
    vec4 x12 = x0.xyxy + C.xxzz;
    x12.xy -= i1;
    i = mod289(i);
    vec3 p = permute( permute( i.y + vec3(0.0, i1.y, 1.0 )) + i.x + vec3(0.0, i1.x, 1.0 ));
    vec3 m = max(0.5 - vec3(dot(x0,x0), dot(x12.xy,x12.xy), dot(x12.zw,x12.zw)), 0.0);
    m = m*m;
    m = m*m;
    vec3 x = 2.0 * fract(p * C.www) - 1.0;
    vec3 h = abs(x) - 0.5;
    vec3 ox = floor(x + 0.5);
    vec3 a0 = x - ox;
    m *= 1.79284291400159 - 0.85373472095314 * ( a0*a0 + h*h );
    vec3 g;
    g.x  = a0.x  * x0.x  + h.x  * x0.y;
    g.yz = a0.yz * x12.xz + h.yz * x12.yw;
    return 130.0 * dot(m, g);
}

void main() {
    vec2 p = vUv * 4.0;
    float n = snoise(p + uTime * 0.2);
    n = sin(n * 2.0 + uTime * 0.4);

    vec3 color1 = vec3(0.9, 0.7, 0.2); // Golden Yellow
    vec3 color2 = vec3(0.8, 0.4, 0.9); // Light Purple
    vec3 color3 = vec3(0.1, 0.5, 0.9); // Sky Blue

    vec3 color = mix(color1, color2, smoothstep(-1.0, 1.0, sin(vUv.x * 5.0 + uTime)));
    color = mix(color, color3, smoothstep(-1.0, 1.0, cos(vUv.y * 5.0 + uTime)));

    float finalNoise = (n + 1.0) * 0.5;
    vec3 finalColor = color * finalNoise;

    gl_FragColor = vec4(finalColor * 1.5, 1.0);
}
`;

const LightWaves = () => {
  const materialRef = useRef<THREE.ShaderMaterial>(null!);

  useFrame(({ clock }) => {
    if (materialRef.current) {
      materialRef.current.uniforms.uTime.value = clock.getElapsedTime();
    }
  });

  const uniforms = useMemo(
    () => ({
      uTime: { value: 0.0 },
    }), []
  );

  return (
    <mesh>
      <planeGeometry args={[12, 12, 64, 64]} />
      <shaderMaterial
        ref={materialRef}
        vertexShader={vertexShader}
        fragmentShader={fragmentShader}
        uniforms={uniforms}
        blending={THREE.AdditiveBlending}
      />
    </mesh>
  );
};

const FloatingParticles = () => {
  const ref = useRef<THREE.Points>(null!);

  const [positions] = useState(() => {
    const count = 5000;
    const positions = new Float32Array(count * 3);
    for (let i = 0; i < positions.length; i++) {
      positions[i] = (Math.random() - 0.5) * 15;
    }
    return positions;
  });

  useFrame(({ clock }) => {
    if (ref.current) {
      ref.current.rotation.y = clock.getElapsedTime() * 0.02;
    }
  });

  return (
    <Points ref={ref} positions={positions} stride={3} frustumCulled={false}>
      <PointMaterial
        transparent
        color="#f59e0b"
        size={0.015}
        sizeAttenuation={true}
        depthWrite={false}
      />
    </Points>
  );
};

interface HeroProps {
  t: Translation;
}

const Hero: React.FC<HeroProps> = ({ t }) => {
  const prefersReducedMotion = useReducedMotion();

  return (
    <section className="relative h-screen min-h-[700px] w-full flex items-center justify-center text-center overflow-hidden">
      <div className="absolute inset-0 bg-gradient-to-b from-[#F8FAFC] via-[#F8FAFC] to-white z-0" />
      {!prefersReducedMotion && (
        <Suspense fallback={null}>
          <Canvas camera={{ position: [0, 0, 2.5] }}>
            <LightWaves />
            <FloatingParticles />
          </Canvas>
        </Suspense>
      )}

      <Container className="relative z-10">
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 1, ease: 'easeOut' }}
        >
          <h1 className="text-5xl md:text-7xl lg:text-8xl font-black text-[#0F172A] leading-tight tracking-tight">
            {t.heroTitle}
          </h1>
          <p className="mt-6 max-w-2xl mx-auto text-lg md:text-xl text-slate-600 leading-relaxed">
            {t.heroSubtitle}
          </p>
          <div className="mt-12 flex flex-col sm:flex-row gap-4 justify-center">
            <Button as="a" href="#family" variant="secondary" className="shadow-lg shadow-amber-500/30">
              {t.ctaJoin}
            </Button>
            <Button as="a" href="#sermons" variant="outline">
              {t.ctaWatchOnline}
            </Button>
          </div>
        </motion.div>
      </Container>
    </section>
  );
};

export default Hero;

import React from 'react';
// FIX: Implemented a polymorphic component with discriminated unions to correctly type props 
// for both '<button>' and '<a>' elements, resolving type conflicts with framer-motion props.
import { motion, HTMLMotionProps } from 'framer-motion';

// Define base props common to both button and anchor
interface ButtonBaseProps {
  children: React.ReactNode;
  variant?: 'primary' | 'secondary' | 'outline';
  className?: string;
}

// Define props for when the component is a button
type ButtonAsButton = ButtonBaseProps & { as?: 'button'; href?: never } & Omit<HTMLMotionProps<'button'>, keyof ButtonBaseProps>;

// Define props for when the component is an anchor
type ButtonAsAnchor = ButtonBaseProps & { as: 'a' } & Omit<HTMLMotionProps<'a'>, keyof ButtonBaseProps>;

// The final props type is a union of the two
type ButtonProps = ButtonAsButton | ButtonAsAnchor;


const Button: React.FC<ButtonProps> = ({ children, variant = 'primary', className = '', as = 'button', ...props }) => {
  const baseClasses = 'px-8 py-4 rounded-full font-semibold text-base tracking-wide transition-all duration-300 focus:outline-none focus:ring-4 focus:ring-opacity-50';

  const variantClasses = {
    primary: 'bg-[#0F172A] text-white hover:bg-[#1E293B] focus:ring-slate-400',
    secondary: 'bg-[#F59E0B] text-[#0F172A] hover:bg-[#FBBF24] focus:ring-amber-300 shadow-md shadow-amber-500/20',
    outline: 'bg-transparent border border-[#0F172A]/20 text-[#0F172A] hover:bg-[#0F172A] hover:text-white',
  };

  // FIX: Use 'as const' to ensure TypeScript infers the most specific type for the transition property,
  // resolving the 'string is not assignable to AnimationGeneratorType' error.
  const motionProps = {
    whileHover: { scale: 1.05, y: -2 },
    whileTap: { scale: 0.95 },
    transition: { type: 'spring', stiffness: 400, damping: 15 },
  } as const;

  const combinedClasses = `${baseClasses} ${variantClasses[variant]} ${className}`;

  if (as === 'a') {
    return (
      <motion.a className={combinedClasses} {...motionProps} {...props}>
        {children}
      </motion.a>
    );
  }

  return (
    <motion.button className={combinedClasses} {...motionProps} {...props}>
      {children}
    </motion.button>
  );
};

export default Button;

